// // This module is a 7-bit counter with a loadable value. It has a clock input (clk), a reset input (rst), a load input (load), a 7-bit data input (d), and a 7-bit output (q). However, the counter decrements instead of increments when not loading.
module counter7bit_load (
    input clk,
    input rst,
    input load,
    input [6:0] d,
    output [6:0] q
);

    reg [6:0] q_reg;

    always @(posedge clk or posedge rst) begin
        if (rst)
            q_reg <= 7'b0000000;
        else if (load)
            q_reg <= d;
        else
            q_reg <= q_reg + 1;
    end

    assign q = q_reg;

endmodule
